def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    out: Dict[str, str] = {}
    if not items:
        return out
    for item in items:
        if "=" not in item:
            raise ValueError(f"Invalid key=value item: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid empty key in item: {item}")
        out[k] = v
    return out


def parse_json_or_kv_config(config_json: Optional[str], config_kv: Optional[List[str]]) -> Dict[str, str]:
    cfg: Dict[str, str] = {}
    if config_json:
        try:
            loaded = json.loads(config_json)
        except json.JSONDecodeError as ex:
            raise ValueError(f"Invalid JSON for --config-json: {ex}") from ex
        if not isinstance(loaded, dict):
            raise ValueError("--config-json must be a JSON object")
        for k, v in loaded.items():
            cfg[str(k)] = str(v)
    cfg.update(parse_kv_list(config_kv))
    return cfg


def parse_topics(topics: Optional[List[str]], topics_file: Optional[str]) -> List[str]:
    out: List[str] = []
    if topics:
        out.extend([t.strip() for t in topics if t.strip()])
    if topics_file:
        with open(topics_file, "r", encoding="utf-8") as f:
            for line in f:
                t = line.strip()
                if not t or t.startswith("#"):
                    continue
                out.append(t)
    # de-dup preserving order
    seen = set()
    uniq = []
    for t in out:
        if t not in seen:
            uniq.append(t)
            seen.add(t)
    return uniq


def admin_client_from_args(args) -> KafkaAdminClient:
    security_protocol = args.security_protocol
    sasl_mechanism = args.sasl_mechanism
    sasl_plain_username = args.sasl_username
    sasl_plain_password = args.sasl_password

    if args.sasl_username_env and not sasl_plain_username:
        sasl_plain_username = os.environ.get(args.sasl_username_env)
    if args.sasl_password_env and not sasl_plain_password:
        sasl_plain_password = os.environ.get(args.sasl_password_env)

    kwargs = {
        "bootstrap_servers": args.bootstrap_servers,
        "client_id": args.client_id,
        "request_timeout_ms": args.request_timeout_ms,
        "api_version_auto_timeout_ms": args.api_version_auto_timeout_ms,
    }

    if security_protocol:
        kwargs["security_protocol"] = security_protocol
    if sasl_mechanism:
        kwargs["sasl_mechanism"] = sasl_mechanism
    if sasl_plain_username is not None:
        kwargs["sasl_plain_username"] = sasl_plain_username
    if sasl_plain_password is not None:
        kwargs["sasl_plain_password"] = sasl_plain_password

    if args.ssl_cafile:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    if args.ssl_password:
        kwargs["ssl_password"] = args.ssl_password
    if args.ssl_check_hostname is not None:
        kwargs["ssl_check_hostname"] = args.ssl_check_hostname

    return KafkaAdminClient(**kwargs)


def wait_for_topics(admin: KafkaAdminClient, topics: List[str], timeout_s: int = 60) -> None:
    deadline = time.time() + timeout_s
    remaining = set(topics)
    while remaining and time.time() < deadline:
        try:
            existing = set(admin.list_topics())
        except Exception:
            time.sleep(1)
            continue
        remaining = remaining - existing
        if remaining:
            time.sleep(1)
    if remaining:
        raise TimeoutError(f"Timed out waiting for topics to appear: {sorted(remaining)}")


def cmd_create_topics(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")

    topic_configs = parse_json_or_kv_config(args.config_json, args.config)

    new_topics = []
    for t in topics:
        new_topics.append(
            NewTopic(
                name=t,
                num_partitions=args.partitions,
                replication_factor=args.replication_factor,
                topic_configs=topic_configs if topic_configs else None,
            )
        )

    try:
        admin.create_topics(new_topics=new_topics, validate_only=args.validate_only)
    except TopicAlreadyExistsError as ex:
        if args.if_not_exists:
            return 0
        raise ex

    if args.wait:
        wait_for_topics(admin, topics, timeout_s=args.wait_timeout_s)

    return 0


def cmd_delete_topics(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")
    try:
        admin.delete_topics(topics=topics, timeout_ms=args.timeout_ms)
    except UnknownTopicOrPartitionError as ex:
        if args.if_exists:
            return 0
        raise ex
    return 0


def cmd_list_topics(admin: KafkaAdminClient, args) -> int:
    topics = admin.list_topics()
    for t in sorted(topics):
        print(t)
    return 0


def cmd_describe_topics(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")
    md = admin._client.cluster
    admin._client.poll(timeout_ms=1000)
    # Force metadata update
    admin._client.cluster.request_update()
    admin._client.poll(timeout_ms=1000)

    # kafka-python doesn't expose a stable describe_topics API in AdminClient.
    # We print best-effort metadata from the underlying client.
    for t in topics:
        parts = md.partitions_for_topic(t)
        if parts is None:
            print(json.dumps({"topic": t, "error": "UNKNOWN_TOPIC_OR_PARTITION"}))
            continue
        partitions = []
        for p in sorted(parts):
            leader = md.leader_for_partition((t, p))
            replicas = md.replicas_for_partition((t, p)) or []
            isr = md.isr_for_partition((t, p)) or []
            partitions.append(
                {
                    "partition": p,
                    "leader": leader,
                    "replicas": list(replicas),
                    "isr": list(isr),
                }
            )
        print(json.dumps({"topic": t, "partitions": partitions}, sort_keys=True))
    return 0


def cmd_increase_partitions(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")
    if args.total_partitions is None and args.add_partitions is None:
        raise ValueError("Provide either --total-partitions or --add-partitions.")
    if args.total_partitions is not None and args.add_partitions is not None:
        raise ValueError("Provide only one of --total-partitions or --add-partitions.")

    # Determine current partitions via metadata
    admin._client.poll(timeout_ms=1000)
    admin._client.cluster.request_update()
    admin._client.poll(timeout_ms=1000)
    md = admin._client.cluster

    topic_partitions: Dict[str, int] = {}
    for t in topics:
        parts = md.partitions_for_topic(t)
        if parts is None:
            raise UnknownTopicOrPartitionError(f"Unknown topic: {t}")
        current = len(parts)
        if args.total_partitions is not None:
            new_total = args.total_partitions
        else:
            new_total = current + args.add_partitions
        if new_total < current:
            raise ValueError(f"Cannot decrease partitions for {t}: current={current}, requested={new_total}")
        if new_total == current:
            if args.noop_ok:
                continue
            else:
                raise ValueError(f"No change for {t}: already has {current} partitions")
        topic_partitions[t] = new_total

    if not topic_partitions:
        return 0

    admin.create_partitions(topic_partitions=topic_partitions, timeout_ms=args.timeout_ms, validate_only=args.validate_only)
    return 0


def cmd_alter_configs(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")

    cfg = parse_json_or_kv_config(args.config_json, args.config)
    if not cfg:
        raise ValueError("No configs provided. Use --config, --config-json.")

    # kafka-python AdminClient supports alter_configs with resources dict:
    # {('topic', 'name'): {'cleanup.policy': 'compact'}}
    resources = {}
    for t in topics:
        resources[("topic", t)] = cfg

    admin.alter_configs(config_resources=resources)
    return 0


def cmd_describe_configs(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics(args.topics, args.topics_file)
    if not topics:
        raise ValueError("No topics provided. Use --topics and/or --topics-file.")

    resources = [("topic", t) for t in topics]
    resp = admin.describe_configs(config_resources=resources)

    # Response shape varies by kafka-python version; normalize best-effort.
    for res, cfgs in resp.items() if isinstance(resp, dict) else []:
        rtype, rname = res if isinstance(res, tuple) and len(res) == 2 else (None, None)
        out = {"resource_type": rtype, "resource_name": rname, "configs": {}}
        if isinstance(cfgs, dict):
            for k, v in cfgs.items():
                if isinstance(v, dict) and "value" in v:
                    out["configs"][k] = v.get("value")
                else:
                    out["configs"][k] = v
        print(json.dumps(out, sort_keys=True))
    return 0


